const dataFile = require('../../data.json');

const $ = data => {
  const { name } = data;

  const [, _link] = name.match(/^portfolio_works_(\d{8}_.+)$/);
  const link = _link.replace(/_/g, '-');

  return {
    ...data,
    link
  };
};

export const works = datas().map(data => $(data));

function datas() {
  return dataFile;
}
